RVTEST_SIGUPD(x24, x5, x4, x25, Vf32_vmfne_vf_cg_cp_custom_vfp_flags_nv_duplicate_3, test_569_str)# store x25 in signature
vsetivli x0, 1, e8, m1, tu, mu                    # set SEW=8, LMUL=1, VL=1 before signature check
# RVTEST_SIGUPD_V(_CMP, _SIG_PTR, _LINK_REG, _TEMP_REG, _VTMP, _MTMP, _SEW, _OFFSET, _VREG, _INST_PTR, _STR_PTR)
RVTEST_SIGUPD_V(vmxor.mm, x24, x5, x4, v26, v5, 8, 8, v7, Vf32_vmfne_vf_cg_cp_custom_vfp_flags_nv_duplicate_3, test_569_str)# Check if v7 contains the expected result. x24 is the signature ptr, x5 is the link ptr, x4 is a temp reg.

# testgen_footer.S

